const d = $input.first().json;

// ── HTML email builder ─────────────────────────────
const row = (label, value) => {
  if (!value || value.trim() === '') return '';
  return `<tr>
    <td style="padding:9px 14px;background:#F7F8FC;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.07em;color:#9CA3AF;width:38%;border-bottom:1px solid #E8EAF2">${label}</td>
    <td style="padding:9px 14px;font-size:13px;color:#1A1535;border-bottom:1px solid #E8EAF2">${value}</td>
  </tr>`;
};

const priorityBlock = (num, value, color) => {
  if (!value || value.trim() === '') return '';
  return `<div style="padding:10px 14px;background:${color}10;border-left:3px solid ${color};border-radius:0 8px 8px 0;margin-bottom:8px;font-size:13px;color:#1A1535"><strong style="color:${color}">P${num}</strong> — ${value}</div>`;
};

const htmlBody = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"/></head>
<body style="margin:0;padding:20px;background:#F0F2F8;font-family:Inter,Arial,sans-serif">
<div style="max-width:620px;margin:0 auto">

  <!-- Header -->
  <div style="background:linear-gradient(135deg,#F27121 0%,#E94057 40%,#B43072 70%,#8A2387 100%);padding:32px;border-radius:12px 12px 0 0">
    <div style="font-size:13px;font-weight:600;color:rgba(255,255,255,.55);text-transform:uppercase;letter-spacing:.1em;margin-bottom:8px">Heaptrace Technology</div>
    <div style="font-size:24px;font-weight:800;color:#fff;letter-spacing:-.5px">Kickoff Meeting Agenda</div>
    <div style="color:rgba(255,255,255,.5);font-size:13px;margin-top:4px">Confidential · For Client Use Only</div>
  </div>

  <!-- Body -->
  <div style="background:#fff;padding:28px 32px;border:1px solid #E8EAF2;border-top:none">

    <!-- Greeting -->
    <p style="font-size:15px;font-weight:600;color:#1A1535;margin:0 0 8px">Hi ${d.client_name} team,</p>
    <p style="font-size:14px;color:#6B7280;line-height:1.75;margin:0 0 24px">
      Thank you for joining today's kickoff call. The full PDF agenda is attached to this email.
      Below is a quick reference summary of everything we covered and agreed on.
    </p>

    <!-- Meeting Summary -->
    <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#9CA3AF;margin-bottom:10px">Meeting Summary</div>
    <table style="width:100%;border-collapse:collapse;border:1px solid #E8EAF2;border-radius:10px;overflow:hidden;margin-bottom:24px">
      ${row('Client', d.client_name)}
      ${row('Meeting Date', d.meeting_date)}
      ${row('Engagement Type', d.engagement_type)}
      ${row('Cloud Platform', d.access_cloud)}
      ${row('Source Control', d.access_vcs)}
      ${row('Project Management', d.access_pm)}
      ${row('Communication Tool', d.access_comms)}
      ${(d.access_additional || '').trim() ? row('Additional Access', d.access_additional) : ''}
      ${row('Call Cadence', d.call_frequency)}
      ${row('Call Days', d.call_days)}
      ${(d.call_time || '').trim() ? row('Call Time', (d.call_time || '') + (d.call_timezone ? ' ' + d.call_timezone : '')) : ''}
    </table>

    <!-- Priorities -->
    ${(d.priority_1 || d.priority_2 || d.priority_3) ? `
    <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#9CA3AF;margin-bottom:10px">First 2-Week Priorities</div>
    <div style="margin-bottom:24px">
      ${priorityBlock(1, d.priority_1, '#F27121')}
      ${priorityBlock(2, d.priority_2, '#E94057')}
      ${priorityBlock(3, d.priority_3, '#B43072')}
    </div>` : ''}

    <!-- Notes -->
    ${(d.notes_aob || '').trim() ? `
    <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#9CA3AF;margin-bottom:10px">Meeting Notes & Action Items</div>
    <div style="background:#F7F8FC;border-radius:10px;padding:16px;margin-bottom:24px;border:1px solid #E8EAF2">
      <pre style="font-family:Inter,Arial,sans-serif;font-size:13px;color:#1A1535;white-space:pre-wrap;margin:0;line-height:1.75">${d.notes_aob}</pre>
    </div>` : ''}

    <!-- Escalation reminder -->
    <div style="background:#FFF7F0;border:1px solid #FFD9B3;border-radius:10px;padding:14px 16px;margin-bottom:24px">
      <div style="font-size:12px;font-weight:700;color:#F27121;margin-bottom:4px">📞 Escalation Path</div>
      <div style="font-size:13px;color:#6B7280">Day-to-day concerns → <strong style="color:#1A1535">Delivery Manager</strong> &nbsp;·&nbsp; Strategic issues → <strong style="color:#1A1535">Director of Sales</strong></div>
    </div>

    <p style="font-size:13px;color:#6B7280;line-height:1.7;margin:0">
      Please review the attached PDF and reach out if you have any questions or need to adjust anything.
      We're excited to get started and deliver great work for you!
    </p>
    <p style="font-size:13px;color:#6B7280;margin:16px 0 0">Warm regards,<br/><strong style="color:#1A1535">Heaptrace Technology</strong></p>
  </div>

  <!-- Footer -->
  <div style="background:#110E27;padding:16px 32px;border-radius:0 0 12px 12px;text-align:center">
    <div style="font-size:12px;color:rgba(255,255,255,.3)">Prepared by <strong style="color:#F27121">Heaptrace Technology Private Limited</strong> · Confidential</div>
  </div>

</div>
</body>
</html>`;

// ── Prepare result ──────────────────────────────────
const pdfBase64 = d.pdf_base64;
const pdfFilename = d.pdf_filename || `Heaptrace-Kickoff-${(d.client_name || 'Meeting').replace(/\s+/g, '-')}.pdf`;

const result = {
  json: {
    ...d,
    emailTo: d.client_email,
    emailSubject: `Kickoff Meeting Agenda — ${d.client_name}`,
    emailHtml: htmlBody
  }
};

// Attach PDF if provided
if (pdfBase64) {
  result.binary = {
    attachment: await this.helpers.prepareBinaryData(
      Buffer.from(pdfBase64, 'base64'),
      pdfFilename,
      'application/pdf'
    )
  };
}

return [result];
